import{c as s}from"./DSWU3toF.js";const r={async searchFaculty(t){return(await s.get("/faculty/search",{params:{q:t,limit:20}})).data},async getMe(){return(await s.get("/faculty/me")).data},async getFaculty(t){return(await s.get(`/faculty/${t}`)).data},async updateAvailabilityStatus(t){return(await s.put("/faculty/me/availability-status",{availability_status:t})).data},async getApprovals(t){return(await s.get(`/faculty/${t}/approvals`)).data},async processApproval(t,e,a){return(await s.put(`/faculty/${t}/approvals/${e}`,a)).data},async getSchedule(t){return(await s.get(`/faculty/${t}/schedule`)).data},async getNotifications(t){return(await s.get(`/faculty/${t}/notifications`)).data},async getStudents(t){return(await s.get(`/faculty/${t}/students`)).data},async getUnassignedPatients(t){return(await s.get(`/faculty/${t}/patients-unassigned`)).data},async assignPatient(t,e,a){return(await s.post(`/faculty/${t}/assign-patient`,{student_id:e,patient_id:a})).data},async removeAssignment(t,e){await s.delete(`/faculty/${t}/assignments/${e}`)},async uploadPhoto(t){const e=new FormData;return e.append("file",t),(await s.post("/faculty/me/upload-photo",e,{headers:{"Content-Type":"multipart/form-data"}})).data},async getAdmittedPatients(t="Active",e=50,a=0){return(await s.get("/admissions/",{params:{status:t,limit:e,offset:a}})).data},async getFacultyClinics(t){return(await s.get(`/clinics/faculty/${t}/clinics`)).data},async getClinicSessions(t){return(await s.get(`/faculty/${t}/clinic-sessions`)).data},async checkInToClinic(t,e){return(await s.post(`/faculty/${t}/clinic-sessions/check-in`,{clinic_id:e})).data},async checkOutFromClinic(t,e){return(await s.post(`/faculty/${t}/clinic-sessions/${e}/check-out`)).data},async getClinicPatients(t){return(await s.get(`/clinics/${t}/patients`)).data},async uploadSignature(t){const e=new FormData;return e.append("file",t),(await s.post("/faculty/me/upload-signature",e,{headers:{"Content-Type":"multipart/form-data"}})).data},async markNotificationsRead(t){return(await s.put(`/faculty/${t}/notifications/read`)).data},async getTodaySchedule(t){return(await s.get(`/faculty/${t}/today-schedule`)).data},async createScheduleItem(t,e){return(await s.post(`/faculty/${t}/schedule`,e)).data},async updateScheduleItem(t,e,a){return(await s.put(`/faculty/${t}/schedule/${e}`,a)).data},async deleteScheduleItem(t,e){return(await s.delete(`/faculty/${t}/schedule/${e}`)).data}};export{r as f};
